#include <stdio.h>
#include <stdlib.h>

int main() {
    FILE *fp;
    long fileSize;

    fp = fopen("data.dat", "rb");
    if (fp == NULL) {
        printf("File cannot be opened.\n");
        return 1;
    }

    // Move to end of file
    if (fseek(fp, 0, SEEK_END) != 0) {
        printf("fseek failed.\n");
        fclose(fp);
        return 1;
    }

    // Get current position (which is file size)
    fileSize = ftell(fp);
    printf("File size: %ld bytes\n", fileSize);

    fclose(fp);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

struct Student {
    int roll;
    char name[30];
    float marks;
};

int main() {
    FILE *fp;
    struct Student s;
    int recordNum;

    fp = fopen("students.dat", "rb");
    if (fp == NULL) {
        printf("Error opening file.\n");
        return 1;
    }

    printf("Enter record number to read (1-based): ");
    scanf("%d", &recordNum);

    // Calculate offset: (recordNum - 1) * size of each record
    // Using 0-based indexing internally
    if (fseek(fp, (recordNum - 1) * sizeof(struct Student), SEEK_SET) != 0) {
        printf("Error seeking to record.\n");
        fclose(fp);
        return 1;
    }

    // Read the record
    if (fread(&s, sizeof(struct Student), 1, fp) == 1) {
        printf("Roll: %d\n", s.roll);
        printf("Name: %s\n", s.name);
        printf("Marks: %.2f\n", s.marks);
    } else {
        printf("Record not found or read error.\n");
    }

    fclose(fp);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

struct Employee {
    int empId;
    char name[40];
    float salary;
};

int main() {
    FILE *fp;
    struct Employee emp;
    int targetId;
    float newSalary;

    fp = fopen("employees.dat", "r+b");  // read/write binary
    if (fp == NULL) {
        printf("Cannot open file.\n");
        return 1;
    }

    printf("Enter Employee ID to update: ");
    scanf("%d", &targetId);
    printf("Enter new salary: ");
    scanf("%f", &newSalary);

    // Read and search for employee
    while (fread(&emp, sizeof(struct Employee), 1, fp) == 1) {
        if (emp.empId == targetId) {
            // Move back one record position
            fseek(fp, -sizeof(struct Employee), SEEK_CUR);

            emp.salary = newSalary;

            // Write updated record
            fwrite(&emp, sizeof(struct Employee), 1, fp);
            fflush(fp);  // Ensure data is written to disk

            printf("Salary updated successfully.\n");
            fclose(fp);
            return 0;
        }
    }

    printf("Employee not found.\n");
    fclose(fp);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

struct Product {
    int id;
    char name[30];
    float price;
};

int main() {
    FILE *fp;
    struct Product p;
    long fileSize, numRecords, i;

    fp = fopen("products.dat", "rb");
    if (fp == NULL) {
        printf("Cannot open file.\n");
        return 1;
    }

    // Find file size
    fseek(fp, 0, SEEK_END);
    fileSize = ftell(fp);
    numRecords = fileSize / sizeof(struct Product);

    printf("Records in reverse order:\n");

    // Read from last record to first
    for (i = numRecords; i >= 1; i--) {
        fseek(fp, (i - 1) * sizeof(struct Product), SEEK_SET);
        fread(&p, sizeof(struct Product), 1, fp);

        printf("ID: %d, Name: %s, Price: %.2f\n", 
               p.id, p.name, p.price);
    }

    fclose(fp);
    return 0;
}
